#### Track Expiration Dates and Annuity Due Dates

1. **Calculate Time to Expiry**: Calculate the time remaining until each patent expires.
2. **Determine Annuity Risk**: Determine if annuity payments are due based on current date.

```javascript
function trackExpirationAndAnnuity(priorArtDocuments) {
    const today = new Date();

    priorArtDocuments.forEach(document => {
        const expirationDate = new Date(document.metadata.expiration_date);
        const timeToExpiry = calculateTimeDifference(today, expirationDate);

        document.time_to_expiry = timeToExpiry;

        // Check if annuity payment is due
        const currentYear = today.getFullYear();
        const nextDueDateIndex = document.annuity_due_dates.findIndex(date => new Date(date).getFullYear() > currentYear);

        if (nextDueDateIndex !== -1) {
            document.next_annuity_due_date = document.annuity_due_dates[nextDueDateIndex];
            document.annuity_risk = true;
        } else {
            document.annuity_risk = false;
        }
    });
}

function calculateTimeDifference(date1, date2) {
    const diffInMs = Math.abs(date2 - date1);
    return new Date(diffInMs).toISOString().slice(0, 10); // Returns time difference in YYYY-MM-DD format
}
```

