        "comparison_rows": comparison_rows,
        "dependent_claims": []
    }

    # Process dependent claims
    for claim in dependent_claims:
        if claim['claim_type'] == 'dependent':
            parent_claim = independent_claim  # Assuming the parent is already parsed

            claim_comparison_rows = []

            for element in extract_elements_from_claim(claim['text']):
                matching_elements = find_matching_elements(element, [doc['abstract'] for doc in prior_art_docs])

                if matching_elements:
                    claim_comparison_rows.append({
                        "claim_element": element,
                        "prior_art_elements": matching_elements
                    })

            main_chart["dependent_claims"].append({
                "claim_id": claim["claim_id"],
                "text": claim['text'],
                "prior_art_document_ids": [doc['patent_id'] for doc in prior_art_docs],
                "comparison_rows": claim_comparison_rows
