### Implementation Example

```python
def generate_claim_chart(parsed_claims, filtered_prior_art):
    chart = {
        "independent_claim": None,
        "dependent_claims": []
    }

    # Initialize the independent claim section
    for claim in parsed_claims:
        if claim['claim_type'] == 'independent':
            chart["independent_claim"] = {
                "claim_number": claim["number"],
                "text": claim["text"],
                "prior_art": []
            }

            # Find relevant prior art documents
            for doc in filtered_prior_art:
                similarity_score = get_similarity(claim['text'], doc['abstract'])

                if similarity_score >= 0.5:  # Threshold for similarity score
                    chart["independent_claim"]["prior_art"].append({
                        "document_id": doc["document_id"],
                        "title": doc["title"],
                        "similarity_score": similarity_score,
                        "relevant_text": get_relevant_text(claim['text'], doc['abstract'])
                    })

    # Initialize dependent claims section
    for claim in parsed_claims:
        if claim['claim_type'] == 'dependent':
            chart["dependent_claims"].append({
                "claim_number": claim["number"],
                "text": claim["text"],
                "prior_art": []
            })

            # Find relevant prior art documents
            for doc in filtered_prior_art:
                similarity_score = get_similarity(claim['text'], doc['abstract'])

                if similarity_score >= 0.5:  # Threshold for similarity score
                    chart["dependent_claims"][-1]["prior_art"].append({
                        "document_id": doc["document_id"],
                        "title": doc["title"],
                        "similarity_score": similarity_score,
                        "relevant_text": get_relevant_text(claim['text'], doc['abstract'])
                    })

    return chart

# Example usage
