#### UI-Side Filtering (JavaScript/React)

```javascript
function applyThreshold(threshold) {
    const filteredResults = results.filter(doc => doc.relevance_score >= threshold);
    displayDocuments(filteredResults);
}

// Example usage
applyThreshold(0.6);  // Apply a relevance score threshold of 0.6

// UI component to set and apply thresholds
const ThresholdSlider = ({ onApply }) => {
    const [threshold, setThreshold] = useState(0.5);

    useEffect(() => {
        onApply(threshold);
    }, [threshold]);

    return (
        <div>
            <input type="range" min="0" max="1" step="0.1" value={threshold} onChange={(e) => setThreshold(e.target.value)} />
            <p>Relevance Score Threshold: {threshold}</p>
        </div>
    );
};

// Usage in the UI
<ThresholdSlider onApply={applyThreshold} />;
